import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './UsersPage.css';

const API_BASE_URL = 'http://localhost:5000/api';

function UsersPage() {
  const [users, setUsers] = useState([]);
  const [filteredUsers, setFilteredUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [strandFilter, setStrandFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('all'); // 'all', 'active', 'inactive'
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const [userTestHistory, setUserTestHistory] = useState([]);
  const [formData, setFormData] = useState({
    full_name: '',
    email: '',
    strand: 'STEM',
    gwa: '',
  });

  useEffect(() => {
    fetchUsers();
  }, []);

  useEffect(() => {
    filterUsers();
  }, [users, search, strandFilter, statusFilter]);

  const fetchUsers = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`${API_BASE_URL}/users`);
      setUsers(response.data.users || []);
    } catch (err) {
      setError('Failed to load users');
    } finally {
      setLoading(false);
    }
  };

  const filterUsers = () => {
    let filtered = users;

    if (search) {
      filtered = filtered.filter(u =>
        u.full_name.toLowerCase().includes(search.toLowerCase()) ||
        u.email.toLowerCase().includes(search.toLowerCase())
      );
    }

    if (strandFilter) {
      filtered = filtered.filter(u => u.strand === strandFilter);
    }

    if (statusFilter === 'active') {
      filtered = filtered.filter(u => u.is_active);
    } else if (statusFilter === 'inactive') {
      filtered = filtered.filter(u => !u.is_active);
    }

    setFilteredUsers(filtered);
  };

  const handleAddUser = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API_BASE_URL}/users`, formData);
      setFormData({ full_name: '', email: '', strand: 'STEM', gwa: '' });
      setShowModal(false);
      fetchUsers();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to add user');
    }
  };

  const handleDeleteUser = async (userId) => {
    if (!window.confirm('Are you sure you want to delete this user?')) return;
    try {
      await axios.delete(`${API_BASE_URL}/users/${userId}`);
      fetchUsers();
    } catch (err) {
      setError('Failed to delete user');
    }
  };

  const handleViewDetails = async (user) => {
    setSelectedUser(user);
    try {
      const response = await axios.get(`${API_BASE_URL}/users/${user.user_id}/test-history`);
      setUserTestHistory(response.data.test_history || []);
      setShowDetailModal(true);
    } catch (err) {
      setError('Failed to load user details');
    }
  };

  const handleToggleStatus = async (userId, currentStatus) => {
    try {
      await axios.patch(`${API_BASE_URL}/users/${userId}/status`, {
        is_active: !currentStatus
      });
      fetchUsers();
      setShowDetailModal(false);
    } catch (err) {
      setError('Failed to update user status');
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    const date = new Date(dateString);
    return date.toLocaleDateString() + ' ' + date.toLocaleTimeString();
  };

  const getInactivityDays = (lastActive) => {
    if (!lastActive) return 'Never';
    const lastActiveDate = new Date(lastActive);
    const now = new Date();
    const diffMs = now - lastActiveDate;
    const diffMins = Math.floor(diffMs / (1000 * 60));
    const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
    
    if (diffMins < 60) {
      return diffMins === 0 ? 'Just now' : `${diffMins} min ago`;
    } else if (diffHours < 24) {
      return `${diffHours}h ago`;
    } else {
      return diffDays === 0 ? 'Today' : `${diffDays}d ago`;
    }
  };

  const getOnlineStatus = (lastActive) => {
    if (!lastActive) return 'Offline';
    const lastActiveDate = new Date(lastActive);
    const now = new Date();
    const diffMins = Math.floor((now - lastActiveDate) / (1000 * 60));
    // Online if logged in within last 30 minutes
    return diffMins < 30 ? 'Online' : 'Offline';
  };

  return (
    <div className="page">
      <div className="page-header">
        <h1><i className="fas fa-users"></i> Users Management</h1>
        <p>Manage student accounts and profiles</p>
      </div>

      {error && (
        <div className="alert alert-error">
          <i className="fas fa-exclamation-circle"></i>
          {error}
        </div>
      )}

      <div className="filter-section">
        <input
          type="text"
          placeholder="Search by name or email..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="search-input"
        />
        <select
          value={strandFilter}
          onChange={(e) => setStrandFilter(e.target.value)}
          className="strand-select"
        >
          <option value="">All Strands</option>
          <option value="STEM">STEM</option>
          <option value="HUMSS">HUMSS</option>
          <option value="ABM">ABM</option>
          <option value="TVL">TVL</option>
        </select>
        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="status-select"
        >
          <option value="all">All Status</option>
          <option value="active">Active</option>
          <option value="inactive">Inactive</option>
        </select>
        <button className="btn btn-primary" onClick={() => setShowModal(true)}>
          <i className="fas fa-plus"></i> Add User
        </button>
      </div>

      {loading ? (
        <div className="loading-center">
          <div className="spinner"></div>
          <p>Loading users...</p>
        </div>
      ) : filteredUsers.length === 0 ? (
        <div className="empty-state">
          <i className="fas fa-inbox"></i>
          <p>No users found</p>
        </div>
      ) : (
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Strand</th>
                <th>GWA</th>
                <th>Tests Taken</th>
                <th>Last Active</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredUsers.map((user) => (
                <tr key={user.user_id}>
                  <td><strong>{user.full_name}</strong></td>
                  <td>{user.email}</td>
                  <td><span className="badge">{user.strand}</span></td>
                  <td>{user.gwa || 'N/A'}</td>
                  <td className="text-center">{user.tests_taken || 0}</td>
                  <td className="text-sm">{getInactivityDays(user.last_login)}</td>
                  <td>
                    <span className={`status ${getOnlineStatus(user.last_login) === 'Online' ? 'active' : 'inactive'}`}>
                      {getOnlineStatus(user.last_login)}
                    </span>
                  </td>
                  <td className="actions">
                    <button 
                      className="btn btn-sm btn-info"
                      onClick={() => handleViewDetails(user)}
                      title="View details"
                    >
                      <i className="fas fa-eye"></i>
                    </button>
                    <button className="btn btn-sm btn-secondary">
                      <i className="fas fa-edit"></i>
                    </button>
                    <button
                      className="btn btn-sm btn-danger"
                      onClick={() => handleDeleteUser(user.user_id)}
                    >
                      <i className="fas fa-trash"></i>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {showDetailModal && selectedUser && (
        <div className="modal-overlay" onClick={() => setShowDetailModal(false)}>
          <div className="modal modal-lg" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2><i className="fas fa-user-circle"></i> User Details</h2>
              <button className="close-btn" onClick={() => setShowDetailModal(false)}>
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="modal-body">
              <div className="detail-grid">
                <div className="detail-item">
                  <span className="label">Name:</span>
                  <span className="value">{selectedUser.full_name}</span>
                </div>
                <div className="detail-item">
                  <span className="label">Email:</span>
                  <span className="value">{selectedUser.email}</span>
                </div>
                <div className="detail-item">
                  <span className="label">Strand:</span>
                  <span className="value"><span className="badge">{selectedUser.strand}</span></span>
                </div>
                <div className="detail-item">
                  <span className="label">GWA:</span>
                  <span className="value">{selectedUser.gwa || 'N/A'}</span>
                </div>
                <div className="detail-item">
                  <span className="label">Tests Taken:</span>
                  <span className="value">{selectedUser.tests_taken || 0}</span>
                </div>
                <div className="detail-item">
                  <span className="label">Last Test:</span>
                  <span className="value">{selectedUser.last_test_date ? formatDate(selectedUser.last_test_date) : 'Never'}</span>
                </div>
                <div className="detail-item">
                  <span className="label">Last Login:</span>
                  <span className="value">{selectedUser.last_login ? formatDate(selectedUser.last_login) : 'Never'}</span>
                </div>
                <div className="detail-item">
                  <span className="label">Online Status:</span>
                  <span className={`status ${getOnlineStatus(selectedUser.last_login) === 'Online' ? 'active' : 'inactive'}`}>
                    {getOnlineStatus(selectedUser.last_login)}
                  </span>
                </div>
                <div className="detail-item">
                  <span className="label">Account Status:</span>
                  <span className={`status ${selectedUser.is_active ? 'active' : 'inactive'}`}>
                    {selectedUser.is_active ? 'Active' : 'Inactive'}
                  </span>
                </div>
              </div>

              <div className="test-history" style={{marginTop: '30px'}}>
                <h3><i className="fas fa-history"></i> Assessment History</h3>
                {userTestHistory.length === 0 ? (
                  <p className="empty-text">No assessments taken yet</p>
                ) : (
                  <div className="assessment-history-list">
                    {userTestHistory.map((attempt) => (
                      <div key={attempt.attempt_id} className="assessment-card" style={{
                        background: '#1e293b',
                        borderRadius: '12px',
                        marginBottom: '20px',
                        overflow: 'hidden',
                        border: '1px solid #334155'
                      }}>
                        {/* Assessment Header with Stats */}
                        <div style={{
                          padding: '20px',
                          background: 'linear-gradient(135deg, #1e3a5f 0%, #2d1b4e 100%)',
                          borderBottom: '1px solid #334155'
                        }}>
                          <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px'}}>
                            <h4 style={{margin: 0, color: '#fff', fontSize: '16px'}}>{attempt.test_name}</h4>
                            <span style={{fontSize: '12px', color: '#94a3b8'}}>{formatDate(attempt.attempt_date)}</span>
                          </div>
                          
                          {/* Stats Row */}
                          <div style={{display: 'flex', gap: '30px', justifyContent: 'center'}}>
                            <div style={{textAlign: 'center'}}>
                              <div style={{fontSize: '28px', fontWeight: 'bold', color: '#fff'}}>{attempt.questions_answered || attempt.total_questions}</div>
                              <div style={{fontSize: '12px', color: '#94a3b8', textTransform: 'uppercase'}}>Questions</div>
                            </div>
                            <div style={{textAlign: 'center'}}>
                              <div style={{fontSize: '28px', fontWeight: 'bold', color: '#a855f7'}}>{attempt.traits_count || 0}</div>
                              <div style={{fontSize: '12px', color: '#94a3b8', textTransform: 'uppercase'}}>Traits Found</div>
                            </div>
                            <div style={{textAlign: 'center'}}>
                              <div style={{fontSize: '28px', fontWeight: 'bold', color: '#22c55e'}}>{attempt.confidence || 0}%</div>
                              <div style={{fontSize: '12px', color: '#94a3b8', textTransform: 'uppercase'}}>Confidence</div>
                            </div>
                          </div>
                          
                          {/* Traits Tags */}
                          {attempt.traits_found && attempt.traits_found.length > 0 && (
                            <div style={{marginTop: '15px', display: 'flex', flexWrap: 'wrap', gap: '8px', justifyContent: 'center'}}>
                              {attempt.traits_found.map((trait, idx) => (
                                <span key={idx} style={{
                                  background: '#7c3aed',
                                  color: '#fff',
                                  padding: '4px 12px',
                                  borderRadius: '20px',
                                  fontSize: '11px',
                                  fontWeight: '500'
                                }}>{trait}</span>
                              ))}
                            </div>
                          )}
                        </div>
                        
                        {/* Top Course Recommendations */}
                        <div style={{padding: '20px'}}>
                          <h5 style={{margin: '0 0 15px 0', color: '#94a3b8', fontSize: '13px', textTransform: 'uppercase', fontWeight: '600'}}>
                            <i className="fas fa-graduation-cap" style={{marginRight: '8px'}}></i>
                            Top Course Recommendations
                          </h5>
                          
                          {attempt.top_courses && attempt.top_courses.length > 0 ? (
                            <div style={{display: 'flex', flexDirection: 'column', gap: '12px'}}>
                              {attempt.top_courses.map((course, idx) => (
                                <div key={idx} style={{
                                  background: '#0f172a',
                                  borderRadius: '10px',
                                  padding: '15px',
                                  border: `2px solid ${idx === 0 ? '#22c55e' : idx === 1 ? '#3b82f6' : '#6366f1'}`,
                                  position: 'relative'
                                }}>
                                  {/* Rank Badge */}
                                  <div style={{
                                    position: 'absolute',
                                    top: '-10px',
                                    right: '15px',
                                    background: idx === 0 ? '#22c55e' : idx === 1 ? '#3b82f6' : '#6366f1',
                                    color: '#fff',
                                    width: '28px',
                                    height: '28px',
                                    borderRadius: '50%',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    fontSize: '12px',
                                    fontWeight: 'bold'
                                  }}>#{idx + 1}</div>
                                  
                                  <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px'}}>
                                    <h6 style={{margin: 0, color: '#fff', fontSize: '14px', fontWeight: '600', flex: 1, paddingRight: '40px'}}>
                                      {course.course_name}
                                    </h6>
                                    <span style={{
                                      color: idx === 0 ? '#22c55e' : idx === 1 ? '#3b82f6' : '#a855f7',
                                      fontWeight: 'bold',
                                      fontSize: '14px'
                                    }}>{course.match_percentage}%</span>
                                  </div>
                                  
                                  {/* Match Bar */}
                                  <div style={{
                                    background: '#1e293b',
                                    borderRadius: '4px',
                                    height: '6px',
                                    marginBottom: '10px',
                                    overflow: 'hidden'
                                  }}>
                                    <div style={{
                                      width: `${course.match_percentage}%`,
                                      height: '100%',
                                      background: idx === 0 ? '#22c55e' : idx === 1 ? '#3b82f6' : '#6366f1',
                                      borderRadius: '4px',
                                      transition: 'width 0.3s ease'
                                    }}></div>
                                  </div>
                                  
                                  {course.course_description && (
                                    <p style={{margin: '0 0 10px 0', color: '#94a3b8', fontSize: '12px', lineHeight: '1.5'}}>
                                      {course.course_description}
                                    </p>
                                  )}
                                  
                                  {/* Trait Tag */}
                                  {course.trait_tag && (
                                    <div style={{display: 'flex', flexWrap: 'wrap', gap: '6px', marginBottom: '10px'}}>
                                      <span style={{
                                        background: '#1e293b',
                                        color: '#60a5fa',
                                        padding: '3px 8px',
                                        borderRadius: '4px',
                                        fontSize: '10px',
                                        border: '1px solid #334155'
                                      }}>{course.trait_tag}</span>
                                    </div>
                                  )}
                                  
                                  {/* Reasoning */}
                                  <div style={{
                                    background: '#1e293b',
                                    borderRadius: '6px',
                                    padding: '10px',
                                    borderLeft: '3px solid #6366f1'
                                  }}>
                                    <p style={{margin: 0, fontSize: '12px', color: '#94a3b8', fontStyle: 'italic'}}>
                                      <strong style={{color: '#a5b4fc'}}>Why this course:</strong> {course.reasoning || 'Based on your assessment results and identified traits.'}
                                    </p>
                                  </div>
                                </div>
                              ))}
                            </div>
                          ) : (
                            <p style={{color: '#64748b', fontSize: '13px', textAlign: 'center', padding: '20px'}}>
                              No course recommendations available for this assessment.
                            </p>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
            <div className="modal-footer">
              <button 
                className={`btn ${selectedUser.is_active ? 'btn-warning' : 'btn-success'}`}
                onClick={() => handleToggleStatus(selectedUser.user_id, selectedUser.is_active)}
              >
                <i className={`fas fa-${selectedUser.is_active ? 'ban' : 'check'}`}></i>
                {selectedUser.is_active ? 'Deactivate Account' : 'Activate Account'}
              </button>
              <button type="button" className="btn btn-secondary" onClick={() => setShowDetailModal(false)}>
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2><i className="fas fa-user-plus"></i> Add New User</h2>
              <button className="close-btn" onClick={() => setShowModal(false)}>
                <i className="fas fa-times"></i>
              </button>
            </div>
            <form onSubmit={handleAddUser}>
              <div className="modal-body">
                <div className="form-group">
                  <label>Full Name</label>
                  <input
                    type="text"
                    value={formData.full_name}
                    onChange={(e) => setFormData({ ...formData, full_name: e.target.value })}
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Email</label>
                  <input
                    type="email"
                    value={formData.email}
                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Strand</label>
                  <select
                    value={formData.strand}
                    onChange={(e) => setFormData({ ...formData, strand: e.target.value })}
                  >
                    <option value="STEM">STEM</option>
                    <option value="HUMSS">HUMSS</option>
                    <option value="ABM">ABM</option>
                    <option value="TVL">TVL</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>GWA (General Weighted Average)</label>
                  <input
                    type="number"
                    min="0"
                    max="100"
                    step="0.01"
                    value={formData.gwa}
                    onChange={(e) => setFormData({ ...formData, gwa: e.target.value })}
                    required
                  />
                </div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-secondary" onClick={() => setShowModal(false)}>
                  Cancel
                </button>
                <button type="submit" className="btn btn-primary">
                  Add User
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default UsersPage;
